import{_ as a,o as t,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const d=JSON.parse('{"title":"Team Practice","description":"","frontmatter":{},"headers":[],"relativePath":"practice/team-practice.md","filePath":"practice/team-practice.md"}'),n={name:"practice/team-practice.md"};function o(c,e,l,s,g,p){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="team-practice" tabindex="-1">Team Practice <a class="header-anchor" href="#team-practice" aria-label="Permalink to &quot;Team Practice&quot;">​</a></h1><p>Team practice sessions track data across your full roster during a practice. All four loggers are available — pitching, at-bat, fielding, and baserunning.</p><h2 id="common-team-practice-scenarios" tabindex="-1">Common Team Practice Scenarios <a class="header-anchor" href="#common-team-practice-scenarios" aria-label="Permalink to &quot;Common Team Practice Scenarios&quot;">​</a></h2><h3 id="bullpen-session" tabindex="-1">Bullpen Session <a class="header-anchor" href="#bullpen-session" aria-label="Permalink to &quot;Bullpen Session&quot;">​</a></h3><p>Log every pitch thrown during bullpen work using the Pitching Logger. Select the pitcher at the top of the screen and log each pitch with type, location, and result. Bullpen data counts toward pitching analytics and helps track command development between games.</p><h3 id="batting-practice" tabindex="-1">Batting Practice <a class="header-anchor" href="#batting-practice" aria-label="Permalink to &quot;Batting Practice&quot;">​</a></h3><p>Log at-bats during live BP rounds using the At-Bat Logger and Pitching Logger together. This gives you spray chart and contact type data on every hitter without needing a live game.</p><h3 id="fielding-drills" tabindex="-1">Fielding Drills <a class="header-anchor" href="#fielding-drills" aria-label="Permalink to &quot;Fielding Drills&quot;">​</a></h3><p>Log fielding repetitions using the Fielding Logger. This is particularly useful for tracking which players need work on specific ball types (ground balls, fly balls) or directional zones.</p><h3 id="voice-logging-at-practice" tabindex="-1">Voice Logging at Practice <a class="header-anchor" href="#voice-logging-at-practice" aria-label="Permalink to &quot;Voice Logging at Practice&quot;">​</a></h3><p>Voice logging is especially efficient at practice where repetitions happen faster than manual entry allows. A parent volunteer with the Voice Logger can track a full bullpen session or batting practice round without slowing down the drill.</p><h2 id="multiple-loggers-at-once" tabindex="-1">Multiple Loggers at Once <a class="header-anchor" href="#multiple-loggers-at-once" aria-label="Permalink to &quot;Multiple Loggers at Once&quot;">​</a></h2><p>During team practice multiple coaches or parents can be logging simultaneously from different devices. All data syncs to the same session in real time.</p><p>For example:</p><ul><li>One coach logs pitching from behind the mound</li><li>A parent volunteer logs hitting from behind the backstop using voice logging</li><li>Both streams appear in the same session analytics</li></ul>',15)])])}const u=a(n,[["render",o]]);export{d as __pageData,u as default};
